import os
import sys
import threading
import queue
from datetime import datetime


class ServerConfig:
    """Server configuration loaded from environment variables."""

    DEFAULTS = {
        'HOST': '127.0.0.1',
        'PORT': '9000',
        'LOG_LEVEL': 'INFO',
        'DATA_DIR': './data',
    }

    def __init__(self):
        self._config = {}
        for key, default in self.DEFAULTS.items():
            env_key = f'SERVER_{key}'
            self._config[key] = os.environ.get(env_key, default)
        os.makedirs(self._config['DATA_DIR'], exist_ok=True)

    def get(self, key, default=None):
        return self._config.get(key, default)


def parse_args(argv):
    """Parse command-line arguments for the server."""
    result = {'command': None, 'host': None, 'port': None, 'daemon': False}
    i = 0
    while i < len(argv):
        arg = argv[i]
        if arg in ('start', 'stop', 'status', 'restart'):
            result['command'] = arg
        elif arg == '--host' and i + 1 < len(argv):
            i += 1
            result['host'] = argv[i]
        elif arg == '--port' and i + 1 < len(argv):
            i += 1
            result['port'] = argv[i]
        elif arg == '--daemon':
            result['daemon'] = True
        i += 1
    return result


class PIDFile:
    """Manages a PID file for tracking the server process."""

    def __init__(self, path):
        self.path = path

    def write(self, pid):
        with open(self.path, 'w') as f:
            f.write(str(pid))

    def read(self):
        try:
            with open(self.path, 'r') as f:
                return int(f.read().strip())
        except FileNotFoundError:
            return None

    def remove(self):
        try:
            os.remove(self.path)
        except FileNotFoundError:
            pass


class Logger:
    """File-based logger with timestamped entries and rotation."""

    def __init__(self, log_path, max_bytes=1_000_000):
        self.log_path = log_path
        self.max_bytes = max_bytes
        os.makedirs(os.path.dirname(log_path) or '.', exist_ok=True)

    def _write(self, level, message):
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        entry = f'[{timestamp}] {level}: {message}\n'
        with open(self.log_path, 'a') as f:
            f.write(entry)
        self._rotate()

    def _rotate(self):
        try:
            if os.path.getsize(self.log_path) > self.max_bytes:
                os.replace(self.log_path, self.log_path + '.1')
        except FileNotFoundError:
            pass

    def info(self, message):
        self._write('INFO', message)

    def error(self, message):
        self._write('ERROR', message)

    def warning(self, message):
        self._write('WARNING', message)


